commands.script:
import time
import random
from app.utils.human_mouse import cdp_precise_click, smooth_move_mouse

ui = command_ui if isinstance(command_ui, dict) else {}
config = ui.get('values') if isinstance(ui.get('values'), dict) else ui

def _as_int(val, default):
    try:
        return int(val)
    except Exception:
        return default

def _as_float(val, default):
    try:
        return float(val)
    except Exception:
        return default

def _as_text(val, default):
    return str(val).strip() if val else default

def _raise_if_stopped():
    raise_if_cancelled()
    raise_if_command_loop_cancelled()

def _with_random_insert(text, chars):
    base = str(text or "")
    pool = str(chars or "")
    if not base or not pool:
        return base
    pos = random.randint(0, len(base))
    return base[:pos] + random.choice(pool) + base[pos:]

def _sleep(sec, step=0.2):
    deadline = time.time() + max(0.0, float(sec or 0.0))
    while time.time() < deadline:
        _raise_if_stopped()
        reset_timeout()
        time.sleep(min(step, max(0.0, deadline - time.time())))
    _raise_if_stopped()
    reset_timeout()

def _probe_ele(selector, timeout=0.5):
    _raise_if_stopped()
    try:
        return tab.ele(selector, timeout=timeout)
    except Exception:
        return None

def _is_displayed(ele):
    try:
        return bool(ele and ele.states.is_displayed)
    except Exception:
        return False

def _current_url():
    try:
        value = tab.run_js("return location.href")
        if value:
            return str(value).strip()
    except Exception:
        pass
    for attr in ('url', 'current_url'):
        try:
            value = str(getattr(tab, attr, '') or '').strip()
        except Exception:
            value = ""
        if value:
            return value
    return ""

def _short_value(value, limit=160):
    text = str(value or "").replace('\r', ' ').replace('\n', ' ').strip()
    if len(text) <= int(limit or 160):
        return text
    return text[:max(0, int(limit or 160) - 3)] + "..."

def _looks_like_session_url(url):
    text = str(url or "").strip().lower()
    if not text:
        return False
    path = text.split('?', 1)[0].split('#', 1)[0]
    if '/c/' in path or '/chat/' in path or '/conversation' in path:
        return True
    if 'arena.ai' not in path and 'lmarena.ai' not in path:
        return False
    ignored = {'http:', 'https:', '', 'arena.ai', 'www.arena.ai', 'lmarena.ai', 'www.lmarena.ai', 'text', 'direct', 'side-by-side', 'image', 'battle'}
    for part in path.split('/'):
        token = part.strip()
        if token in ignored:
            continue
        compact = token.replace('-', '').replace('_', '')
        if len(compact) >= 10 and any(ch.isdigit() for ch in compact):
            return True
    return False

def _message_input_length():
    try:
        value = tab.run_js("""
            return (() => {
                const visible = (el) => {
                    if (!(el instanceof HTMLElement) || !el.isConnected) return false;
                    const r = el.getBoundingClientRect();
                    const s = window.getComputedStyle(el);
                    return r.width > 0 && r.height > 0 && s.display !== 'none' && s.visibility !== 'hidden';
                };
                const inputs = Array.from(document.querySelectorAll("textarea[name='message'], textarea"));
                const input = inputs.find(visible) || inputs[0] || null;
                return input ? String(input.value || '').length : -1;
            })();
        """)
        return int(value)
    except Exception:
        return -1

def _wait_for_new_chat_ready(before_url, timeout_sec=10.0):
    before = str(before_url or '').strip()
    deadline = time.time() + max(0.5, float(timeout_sec or 0.0))
    started_at = time.time()
    latest_url = before
    while time.time() < deadline:
        _raise_if_stopped()
        reset_timeout()
        latest_url = _current_url()
        if before and latest_url and latest_url != before:
            logger.info(f"[Auto-Battle] New Chat 已切换页面: before={_short_value(before, 120)}, current={_short_value(latest_url, 120)}")
            return True
        if not _looks_like_session_url(before) and _message_input_length() == 0 and time.time() - started_at >= 0.8:
            logger.warning("[Auto-Battle] New Chat 后未检测到 URL 切换，但当前不像旧会话页且输入框已清空，继续本轮。")
            return True
        _sleep(0.2, 0.05)
    logger.warning(f"[Auto-Battle] New Chat 后未在 {float(timeout_sec or 0.0):g} 秒内确认页面切换，本次点击视为失败。 latest={_short_value(latest_url, 120)}")
    return False

def _is_clickable_element(ele):
    _raise_if_stopped()
    if not ele:
        return False
    try:
        result = ele.run_js("""
            return (() => {
                const el = this;
                if (!(el instanceof HTMLElement) || !el.isConnected) return false;
                const disabledHost = el.closest('[disabled], [aria-disabled="true"], [data-disabled="true"], [inert]');
                if (disabledHost) return false;
                if (el.disabled || el.getAttribute('aria-disabled') === 'true' || el.getAttribute('data-disabled') === 'true') return false;
                const rect = el.getBoundingClientRect();
                if (!rect || rect.width < 8 || rect.height < 8) return false;
                const vw = window.innerWidth || document.documentElement.clientWidth || 0;
                const vh = window.innerHeight || document.documentElement.clientHeight || 0;
                if (rect.bottom <= 0 || rect.right <= 0 || rect.top >= vh || rect.left >= vw) return false;
                const style = window.getComputedStyle(el);
                if (style.display === 'none' || style.visibility === 'hidden' || style.pointerEvents === 'none') return false;
                if (Number(style.opacity || '1') <= 0.2) return false;
                const x = Math.max(0, Math.min(vw - 1, rect.left + rect.width / 2));
                const y = Math.max(0, Math.min(vh - 1, rect.top + rect.height / 2));
                const top = document.elementFromPoint(x, y);
                if (!top) return false;
                const owner = top.closest ? top.closest('button, [role="button"], a') : null;
                return top === el || el.contains(top) || owner === el || (owner && el.contains(owner));
            })();
        """)
        return bool(result)
    except Exception:
        return False

def _click_element_center(ele, label, jitter=2, move_offset=36):
    _raise_if_stopped()
    if not ele:
        return False
    pos = None
    try:
        try:
            ele.scroll.to_see()
            _sleep(0.1, 0.05)
        except Exception:
            pass
        rect = ele.run_js("""
            const r = this.getBoundingClientRect();
            return {x: Math.round(r.left + r.width / 2), y: Math.round(r.top + r.height / 2), w: r.width, h: r.height};
        """)
        if isinstance(rect, dict) and float(rect.get('w') or 0) > 0 and float(rect.get('h') or 0) > 0:
            pos = (int(rect.get('x')), int(rect.get('y')))
    except Exception:
        pass
    if not pos:
        try:
            r = ele.rect
            for attr in ('viewport_midpoint', 'viewport_click_point', 'midpoint', 'click_point'):
                p = getattr(r, attr, None)
                if p and len(p) >= 2:
                    pos = (int(p[0]), int(p[1]))
                    break
        except Exception:
            pass
    if pos:
        cx = pos[0] + random.randint(-jitter, jitter)
        cy = pos[1] + random.randint(-jitter, jitter)
        logger.info(f"[Auto-Battle] \u51c6\u5907\u70b9\u51fb {label}: ({cx}, {cy})")
        try:
            smooth_move_mouse(tab, (cx - move_offset, cy - move_offset), (cx, cy), check_cancelled=check_cancelled)
        except TypeError:
            smooth_move_mouse(tab, (cx - move_offset, cy - move_offset), (cx, cy))
        _sleep(random.uniform(0.05, 0.12), 0.03)
        return bool(cdp_precise_click(tab, cx, cy, hold_duration=random.uniform(0.025, 0.055), check_cancelled=check_cancelled))
    try:
        result = ele.run_js("""
            try {
                this.scrollIntoView({block: 'center', inline: 'center', behavior: 'instant'});
                this.click();
                return true;
            } catch (error) {
                return false;
            }
        """)
        return bool(result)
    except Exception as e:
        logger.warning(f"[Auto-Battle] JS \u70b9\u51fb {label} \u5931\u8d25: {e}")
        return False

def _visible_vote_button_info():
    _raise_if_stopped()
    try:
        info = tab.run_js("""
            return (() => {
                const norm = (v) => String(v || '').replace(/\\s+/g, ' ').trim().toLowerCase();
                const vw = window.innerWidth || document.documentElement.clientWidth || 0;
                const vh = window.innerHeight || document.documentElement.clientHeight || 0;
                const visible = (el) => {
                    if (!(el instanceof HTMLElement) || !el.isConnected) return false;
                    const rect = el.getBoundingClientRect();
                    if (!rect || rect.width < 8 || rect.height < 8) return false;
                    if (rect.bottom <= 0 || rect.right <= 0 || rect.top >= vh || rect.left >= vw) return false;
                    const style = window.getComputedStyle(el);
                    if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity || '1') <= 0.2) return false;
                    return true;
                };
                const clickable = (el) => {
                    if (!visible(el)) return false;
                    const disabledHost = el.closest('[disabled], [aria-disabled="true"], [data-disabled="true"], [inert]');
                    if (disabledHost) return false;
                    if (el.disabled || el.getAttribute('aria-disabled') === 'true' || el.getAttribute('data-disabled') === 'true') return false;
                    const style = window.getComputedStyle(el);
                    if (style.pointerEvents === 'none') return false;
                    const rect = el.getBoundingClientRect();
                    const x = Math.max(0, Math.min(vw - 1, rect.left + rect.width / 2));
                    const y = Math.max(0, Math.min(vh - 1, rect.top + rect.height / 2));
                    const top = document.elementFromPoint(x, y);
                    if (!top) return false;
                    const owner = top.closest ? top.closest('button, [role="button"], a') : null;
                    return top === el || el.contains(top) || owner === el || (owner && el.contains(owner));
                };
                const matchesA = (text) => {
                    const t = norm(text);
                    return t.includes('a \u66f4\u597d') || t.includes('a is better') || t.includes('\U0001f448 a') || t.includes('\u2190 a') || t === 'a better';
                };
                const buttons = Array.from(document.querySelectorAll('button, [role="button"]'));
                for (const el of buttons) {
                    const text = el.innerText || el.textContent || el.getAttribute('aria-label') || '';
                    if (!matchesA(text)) continue;
                    if (!clickable(el)) continue;
                    el.scrollIntoView({ block: 'center', inline: 'center', behavior: 'instant' });
                    const r = el.getBoundingClientRect();
                    return {found: true, clickable: true, text: String(text).replace(/\\s+/g, ' ').trim(), x: Math.round(r.left + r.width / 2), y: Math.round(r.top + r.height / 2), w: Math.round(r.width), h: Math.round(r.height)};
                }
                return {found: false, clickable: false};
            })();
        """)
        return info if isinstance(info, dict) else {'found': False, 'clickable': False}
    except Exception as e:
        logger.debug(f"[Auto-Battle] \u53ef\u70b9\u51fb\u5b8c\u6210\u6309\u94ae JS \u63a2\u6d4b\u5931\u8d25\uff08\u5ffd\u7565\uff09: {e}")
        return {'found': False, 'clickable': False}

