        """)
        return bool(fallback), info
    except Exception as e:
        logger.error(f"[Auto-Battle] \u9875\u9762\u5185\u6295\u7968\u70b9\u51fb\u515c\u5e95\u5931\u8d25: {e}")
        return False, info

def _has_revealed_models():
    _raise_if_stopped()
    try:
        info = tab.run_js("""
            return (() => {
                const text = document.body ? (document.body.innerText || '') : '';
                const hasVote = Array.from(document.querySelectorAll('button, [role="button"]')).some((el) => {
                    const r = el.getBoundingClientRect();
