                });
                const hasModel = /model\\s*[ab]|assistant\\s*[ab]|winner|\u83b7\u80dc|\u6a21\u578b|gpt|claude|gemini|deepseek|qwen|llama/i.test(text);
                return {hasVote, hasModel};
            })();
        """)
        return bool(isinstance(info, dict) and info.get('hasModel') and not info.get('hasVote'))
    except Exception:
        return False


_claude_watch_state = {'started': False, 'pattern': '', 'hit_count': 0}
_claude_hit_urls = []

def _normalize_network_text(value):
    if value is None:
        return ""
    try:
        if hasattr(value, 'decode'):
            return value.decode('utf-8', errors='ignore')
    except Exception:
        pass
    try:
        return str(value)
    except Exception:
        return ""

def _read_network_response_text(response):
    parts = []
    source = ""
    try:
        stream = getattr(response, '_stream', None)
        if isinstance(stream, dict):
            text = _normalize_network_text(stream.get('fullText') or stream.get('text') or '')
            if text:
                parts.append(text)
                source = source or 'drission_stream'
    except Exception:
        pass
    for obj_name in ('response', 'body_holder', 'raw_response'):
        try:
            obj = getattr(response, obj_name, None)
        except Exception:
            obj = None
        if not obj:
            continue
        for attr in ('body', 'text', 'content'):
            try:
                text = _normalize_network_text(getattr(obj, attr, ''))
            except Exception:
                text = ""
            if text:
                parts.append(text)
                source = source or f'{obj_name}.{attr}'
    try:
        direct_body = _normalize_network_text(getattr(response, 'body', ''))
        if direct_body:
            parts.append(direct_body)
            source = source or 'response.body'
    except Exception:
        pass
    return "\n".join(parts), source or 'unknown'

def _network_response_url(response):
    for obj_name in ('request', 'response'):
        try:
            obj = getattr(response, obj_name, None)
        except Exception:
            obj = None
        if not obj:
            continue
        for attr in ('url', 'target', 'address'):
            try:
                value = str(getattr(obj, attr, '') or '').strip()
            except Exception:
                value = ""
            if value:
                return value
    try:
        return str(getattr(response, 'url', '') or '').strip()
    except Exception:
        return ""

def _stop_claude_network_watch():
    try:
        listen = getattr(tab, 'listen', None)
        if not listen:
            return
        try:
            listen.stop()
        except Exception:
            pass
        try:
            listen.clear()
        except Exception:
            pass
    except Exception:
        pass
    _claude_watch_state['started'] = False
    _claude_watch_state['pattern'] = ''

def _ensure_claude_network_watch(pattern):
    pattern_text = str(pattern or '').strip() or 'nextjs-api/stream/create-evaluation'
    try:
        listen = getattr(tab, 'listen', None)
    except Exception:
        listen = None
    if not listen:
        _claude_watch_state['started'] = False
        logger.warning("[Auto-Battle][CLAUDE-WATCH] \\u5f53\\u524d tab \\u4e0d\\u652f\\u6301\\u7f51\\u7edc\\u76d1\\u542c\\uff0c\\u8df3\\u8fc7 Claude \\u68c0\\u6d4b")
        return False
    if _claude_watch_state.get('started') and _claude_watch_state.get('pattern') == pattern_text:
        try:
            if getattr(listen, 'listening', True):
                return True
        except Exception:
            return True
        _claude_watch_state['started'] = False
        logger.warning("[Auto-Battle][CLAUDE-WATCH] \\u68c0\\u6d4b\\u5230\\u76d1\\u542c\\u5df2\\u505c\\u6b62\\uff0c\\u5c06\\u91cd\\u542f")
    try:
        _stop_claude_network_watch()
        try:
            tab.listen._reuse_driver = True
        except Exception:
            pass
        tab.listen.start(pattern_text)
        _claude_watch_state['started'] = True
        _claude_watch_state['pattern'] = pattern_text
        logger.info(f"[Auto-Battle][CLAUDE-WATCH] \\u5df2\\u542f\\u52a8\\u6301\\u7eed\\u7f51\\u7edc\\u76d1\\u542c: {pattern_text}")
        return True
    except Exception as e:
        _claude_watch_state['started'] = False
        logger.warning(f"[Auto-Battle][CLAUDE-WATCH] \\u7f51\\u7edc\\u76d1\\u542c\\u542f\\u52a8\\u5931\\u8d25\\uff08\\u5ffd\\u7565\\uff09: {e}")
        return False

def _log_claude_hit(text, url='', source=''):
    lower = str(text or '').lower()
    idx = lower.find('claude')
    if idx < 0:
        return False
    raw = str(text or '')
    start = max(0, idx - 120)
    end = min(len(raw), idx + 180)
    preview = raw[start:end].replace('\r', ' ').replace('\n', ' ').strip()
    _claude_watch_state['hit_count'] = int(_claude_watch_state.get('hit_count') or 0) + 1
    hit_url = str(url or _current_url() or '').strip()
    logger.warning("[Auto-Battle][CLAUDE-HIT] ##################################################")
    logger.warning("[Auto-Battle][CLAUDE-HIT] !!! \u68c0\u6d4b\u5230\u6700\u7ec8\u53ef\u89c1\u6587\u672c\u5305\u542b claude !!!")
    logger.warning(f"[Auto-Battle][CLAUDE-HIT] URL: {hit_url or '-'}")
    if hit_url and hit_url not in _claude_hit_urls:
        _claude_hit_urls.append(hit_url)
    logger.warning(f"[Auto-Battle][CLAUDE-HIT] hit_count={_claude_watch_state['hit_count']} source={source or '-'}")
    logger.warning(f"[Auto-Battle][CLAUDE-HIT] preview={preview[:360]}")
    logger.warning("[Auto-Battle][CLAUDE-HIT] ##################################################")
    try:
        record_command_loop_request(
            response_text=f"CLAUDE-HIT source={source or '-'} url={hit_url or '-'} preview={preview[:360]}",
            request_type="Arena \u811a\u672c\u5faa\u73af / Claude \u547d\u4e2d",
        )
    except Exception as e:
        logger.debug(f"[Auto-Battle][CLAUDE-HIT] \u5199\u5165\u8bf7\u6c42\u65e5\u5fd7\u5931\u8d25\uff08\u5ffd\u7565\uff09: {e}")
    return True

def _drain_claude_network_watch(timeout=0.0, max_events=4):
    if not _claude_watch_state.get('started'):
        return False
    deadline = time.time() + max(0.0, float(timeout or 0.0))
    seen = 0
    hit = False
    while seen < max(1, int(max_events or 1)):
        wait_timeout = 0.01
        if timeout and timeout > 0:
            remaining = deadline - time.time()
            if remaining <= 0 and seen > 0:
                break
            wait_timeout = max(0.01, min(0.25, max(0.0, remaining)))
        try:
            response = tab.listen.wait(timeout=wait_timeout)
        except Exception as e:
            _claude_watch_state['started'] = False
            logger.debug(f"[Auto-Battle][CLAUDE-WATCH] \\u7f51\\u7edc\\u76d1\\u542c wait \\u5931\\u8d25\\uff08\\u5ffd\\u7565\\uff09: {e}")
            break
        if not response:
            if not timeout or time.time() >= deadline:
                break
            continue
        seen += 1
        body, source = _read_network_response_text(response)
        if body and 'claude' in body.lower():
            hit = _log_claude_hit(body, url=_network_response_url(response), source=source) or hit
    return hit

def _page_response_info():
    _raise_if_stopped()
    try:
        info = tab.run_js("""
            return (() => {
                const norm = (v) => String(v || '').replace(/\\s+/g, ' ').trim();
                const visible = (el) => {
                    if (!(el instanceof HTMLElement) || !el.isConnected) return false;
                    const r = el.getBoundingClientRect();
                    if (!r || r.width < 4 || r.height < 4) return false;
                    const s = window.getComputedStyle(el);
                    return s.display !== 'none' && s.visibility !== 'hidden' && Number(s.opacity || '1') > 0.15;
                };
                const clickable = (el) => {
                    if (!visible(el)) return false;
                    const disabledHost = el.closest('[disabled], [aria-disabled="true"], [data-disabled="true"], [inert]');
                    if (disabledHost) return false;
                    if (el.disabled || el.getAttribute('disabled') !== null) return false;
                    if (el.getAttribute('aria-disabled') === 'true' || el.getAttribute('data-disabled') === 'true') return false;
                    const s = window.getComputedStyle(el);
                    if (s.pointerEvents === 'none' || s.cursor === 'not-allowed') return false;
                    const r = el.getBoundingClientRect();
                    const vw = window.innerWidth || document.documentElement.clientWidth || 0;
                    const vh = window.innerHeight || document.documentElement.clientHeight || 0;
                    const x = Math.max(0, Math.min(vw - 1, r.left + r.width / 2));
                    const y = Math.max(0, Math.min(vh - 1, r.top + r.height / 2));
                    const top = document.elementFromPoint(x, y);
                    if (!top) return false;
                    const owner = top.closest ? top.closest('button, [role="button"]') : null;
                    return top === el || el.contains(top) || owner === el || (owner && el.contains(owner));
                };
                const textOf = (el) => norm([
                    el.innerText,
                    el.textContent,
                    el.getAttribute('aria-label'),
                    el.getAttribute('title')
                ].filter(Boolean).join(' '));
                const buttons = Array.from(document.querySelectorAll('button, [role="button"]')).filter(visible);
                const isVoteButton = (el) => {
                    const t = textOf(el).toLowerCase();
                    return t.includes('a \u66f4\u597d') || t.includes('b \u66f4\u597d') ||
                        t.includes('a is better') || t.includes('b is better') ||
                        t.includes('a better') || t.includes('b better') ||
                        t.includes('\U0001f448 a') || t.includes('b \U0001f449') ||
                        t.includes('\u2190 a') || t.includes('b \u2192') ||
                        t.includes('both are good') || t.includes('both are bad') ||
                        t.includes('tie') || t.includes('\u90fd\u597d') || t.includes('\u90fd\u4e0d\u597d');
                };
                const voteButtons = buttons.filter(isVoteButton);
                const clickableVoteButtons = voteButtons.filter(clickable);
                const stopButtons = buttons.filter((el) => {
                    const t = textOf(el).toLowerCase();
                    return t.includes('stop generating') || t.includes('stop responding') ||
                        t.includes('stop generation') || t === 'stop' ||
                        t.includes('\u505c\u6b62\u751f\u6210') || t.includes('\u505c\u6b62\u56de\u7b54') ||
                        t.includes('cancel') || t.includes('abort');
                });
                const busyNodes = Array.from(document.querySelectorAll('[aria-busy="true"], [data-loading="true"], [data-state="loading"]')).filter(visible);
                const sendButtons = Array.from(document.querySelectorAll('button[type="submit"], button[aria-label*="Send" i], button[title*="Send" i]')).filter(visible);
                const sendReady = sendButtons.some(clickable);
                const bodyText = norm(document.body ? (document.body.innerText || '') : '');
                const bodyLower = bodyText.toLowerCase();
                const generatingBusy = bodyLower.includes('generating') || bodyLower.includes('loading') ||
                    bodyLower.includes('\u6b63\u5728\u751f\u6210') || bodyLower.includes('\u751f\u6210\u4e2d') ||
                    bodyLower.includes('\u601d\u8003\u4e2d');
                const stableText = bodyText
                    .replace(/\\b\\d{1,2}:\\d{2}\\b/g, '')
                    .replace(/\\b\\d+(?:\\.\\d+)?\\s*(?:s|sec|secs|second|seconds|\u79d2)\\b/gi, '')
                    .replace(/\\s+/g, ' ')
                    .trim();
                const tail = stableText.slice(-12000);
                return {
                    url: String(location.href || ''),
                    done_by_vote: clickableVoteButtons.length > 0 && busyNodes.length === 0 && !generatingBusy,
                    vote_visible: voteButtons.length > 0,
                    vote_clickable: clickableVoteButtons.length > 0,
                    vote_text: voteButtons.slice(0, 4).map(textOf).join(' | '),
                    clickable_vote_text: clickableVoteButtons.slice(0, 4).map(textOf).join(' | '),
                    stop_visible: stopButtons.length > 0,
                    stop_text: stopButtons.slice(0, 3).map(textOf).join(' | '),
                    busy_visible: busyNodes.length > 0 || generatingBusy,
                    generating_text_visible: generatingBusy,
                    send_ready: sendReady,
                    text_len: stableText.length,
                    signature: String(stableText.length) + ':' + tail,
                    visible_text: bodyText,
                    preview: tail.slice(-420)
                };
            })();
        """)
        return info if isinstance(info, dict) else {}
    except Exception as e:
        logger.debug(f"[Auto-Battle] \u9875\u9762\u56de\u590d\u72b6\u6001\u63a2\u6d4b\u5931\u8d25\uff08\u5ffd\u7565\uff09: {e}")
        return {}

def _wait_for_reply_done(timeout_sec=200.0, poll_interval_sec=0.5, baseline_signature=''):
    timeout = min(200.0, max(0.5, float(timeout_sec or 200.0)))
    poll = max(0.2, float(poll_interval_sec or 0.5))
    stable_need = 4.0
    started = time.time()
    deadline = started + timeout
    base_sig = str(baseline_signature or '')
    last_signature = None
    stable_since = None
    saw_changed_text = False
    last_info = {}
    last_log_at = 0.0
    logger.info(f"[Auto-Battle] \u53d1\u9001\u540e\u7b49\u5f85 AI \u8f93\u51fa\u5b8c\u6210\uff0c\u6700\u957f {timeout:g} \u79d2\uff1b\u5b8c\u6210\u540e\u624d\u8fdb\u5165\u4e0b\u4e00\u8f6e New Chat\u3002")
    while time.time() < deadline:
        _raise_if_stopped()
        reset_timeout()
        info = _page_response_info()
        if info:
            last_info = info
            signature = str(info.get('signature') or '')
            text_len = int(info.get('text_len') or 0)
            if signature and signature != base_sig:
                saw_changed_text = True
            if info.get('done_by_vote'):
                logger.info(f"[Auto-Battle] \u68c0\u6d4b\u5230\u53ef\u6309\u4e0b\u7684\u6295\u7968\u6309\u94ae\uff0c\u5224\u5b9a AI \u8f93\u51fa\u5b8c\u6210\uff1bbutton={_short_value(info.get('clickable_vote_text') or info.get('vote_text'), 160)}")
                info['done'] = True
                info['timed_out'] = False
                info['reason'] = 'vote_buttons_visible'
                return info
            active = bool(info.get('stop_visible') or info.get('busy_visible') or (info.get('vote_visible') and not info.get('vote_clickable')))
            if active:
                stable_since = None
            elif saw_changed_text and signature and text_len > 0:
                if signature == last_signature:
                    if stable_since is None:
                        stable_since = time.time()
                    if time.time() - stable_since >= stable_need:
                        logger.info(f"[Auto-Battle] \u9875\u9762\u6587\u672c\u5df2\u7a33\u5b9a {stable_need:g} \u79d2\uff0c\u5224\u5b9a AI \u8f93\u51fa\u5b8c\u6210\uff1burl={_short_value(info.get('url'), 160)}")
                        info['done'] = True
                        info['timed_out'] = False
                        info['reason'] = 'visible_text_stable'
                        return info
                else:
                    last_signature = signature
                    stable_since = time.time()
            if time.time() - last_log_at >= 15.0:
                last_log_at = time.time()
                logger.info(
                    f"[Auto-Battle] \u4ecd\u5728\u7b49\u5f85\u8f93\u51fa\u5b8c\u6210\uff1aelapsed={time.time() - started:.1f}s/{timeout:g}s "
                    f"changed={saw_changed_text} stop={bool(info.get('stop_visible'))} busy={bool(info.get('busy_visible'))} "
                    f"vote_visible={bool(info.get('vote_visible'))} vote_clickable={bool(info.get('vote_clickable'))} "
                    f"send_ready={bool(info.get('send_ready'))} text_len={text_len}"
                )
        _sleep(min(poll, max(0.0, deadline - time.time())), 0.1)
    last_info = last_info if isinstance(last_info, dict) else {}
    last_info['done'] = False
    last_info['timed_out'] = True
    last_info['reason'] = 'timeout'
    last_info['url'] = str(last_info.get('url') or _current_url() or '')
    logger.warning(f"[Auto-Battle] \u7b49\u5f85 AI \u8f93\u51fa\u5b8c\u6210\u8d85\u65f6\uff08{timeout:g} \u79d2\uff09\uff0c\u4e0d\u518d\u7ee7\u7eed\u7b49\uff0c\u76f4\u63a5\u8fdb\u5165\u4e0b\u4e00\u8f6e New Chat\uff1burl={_short_value(last_info.get('url'), 180)}")
    return last_info

def _check_visible_claude_marker(info=None, source='page-final-visible-text'):
    data = info if isinstance(info, dict) else {}
